{
  "competency_groups": [
    {
      "code": "C-2.1",
      "title": "Historical Events and Processes",
      "description": "Explain historical events and processes with different types of sources.",
      "competencies": [
        "Explain historical events and processes with different types of sources with specific examples from India and world history."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-2.3",
      "title": "Continuity and Change in World History",
      "description": "Trace aspects of continuity and change in different phases of world history.",
      "competencies": [
        "Trace aspects of continuity and change in different phases of world history (including cultural trends, social and religious reforms, and economic and political transformations)."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-2.4",
      "title": "Growth of New Ideas and Practices",
      "description": "Explain the growth of new ideas and practices across the world.",
      "competencies": [
        "Explain the growth of new ideas and practices across the world and how they affected the course of world history."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-2.5",
      "title": "Condemned Practices in History",
      "description": "Recognise practices that arose and were later condemned.",
      "competencies": [
        "Recognise the various practices that arose, such as those in C- 2.4, and came to be condemned later on (such as racism, slavery, colonial invasions, conquests, and plunder, genocides, exclusion of women from democratic and other institutions), all of which have also impacted the course of world history and have left unhealed wounds."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C3.2",
      "title": "Indian National Freedom Struggle",
      "description": "Identify and analyse important phases of the Indian national freedom struggle.",
      "competencies": [
        "Identify and analyse important phases of the Indian national freedom struggle against British colonial rule, with special reference to the movement led by Mahatma Gandhi and other important figures as well as those that led to independence."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-4.1",
      "title": "Locating Physiographic Regions",
      "description": "Locate physiographic regions of India and climatic zones.",
      "competencies": [
        "Locate physiographic regions of India and the climatic zones of the world on a globe/map."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-4.2",
      "title": "Geographical Concepts and Landforms",
      "description": "Explain important geographical concepts and characteristics of landforms.",
      "competencies": [
        "Explain important geographical concepts, characteristics of key landforms, their origin, and other physical factors of a region."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-4.3",
      "title": "Inter-linkages in Physical Environment",
      "description": "Draw inter-linkages between components of the physical environment.",
      "competencies": [
        "Draw inter- linkages between various components of the physical environment, such as climate and relief, climate and vegetation, vegetation, and wildlife."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-4.4",
      "title": "Environment-Human Interrelationship",
      "description": "Analyse the inter- relationship between natural environment and human beings.",
      "competencies": [
        "Analyse and evaluate the inter- relationship between the natural environment and human beings and their cultures across regions and, in the case of India, the special environmental ethos that resulted in practices of nature conservation."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-4.5",
      "title": "Impact of Human Interventions on Environment",
      "description": "Critically evaluate the impact of human interventions on the environment.",
      "competencies": [
        "Critically evaluate the impact of human interventions on the environment, including climate change, pollution, shortages of natural resources (particularly water), and loss of biodiversity; identifies practices that have led to these environmental crises and the measures that must be taken to reverse them."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-4.6",
      "title": "Judicious Use of Natural Resources",
      "description": "Develop sensitivity towards the judicious use of natural resources.",
      "competencies": [
        "Develop sensitivity towards the judicious use of natural resources (by individuals, societies, and nations) and suggests measures for their conservation."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-5.1",
      "title": "Indian Constitution and Heritage",
      "description": "Understand that the Indian Constitution draws from cultural heritage.",
      "competencies": [
        "Understand that the Indian Constitution draws from the great cultural heritage and common aspirations of the Indian nation, and recalls India's early experiments with democracy (assemblies in Mahajanapadas , kingdoms and empires at several levels of the society, guilds sanghas and ganas , village councils and committees, Uthiramerur inscriptions)."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-5.2",
      "title": "Constitutional Values",
      "description": "Appreciate fundamental Constitutional values.",
      "competencies": [
        "Appreciate fundamental Constitutional values and identify their significance for the prosperity of the Indian nation."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-5.3",
      "title": "Fundamental Rights and Duties",
      "description": "Explain fundamental rights as basic human rights.",
      "competencies": [
        "Explain that fundamental rights are the most basic human rights, and they flourish when people also perform their fundamental duties."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-5.4",
      "title": "Features of Democracy",
      "description": "Analyse the basic features of a democracy and democratic government.",
      "competencies": [
        "Analyse the basic features of a democracy and democratic government – and its history in India and across the world – and compares this form of government with other forms of government."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-5.5",
      "title": "Non-state Participants in Democracy",
      "description": "Analyse the critical role of non-state and non-market participants.",
      "competencies": [
        "Analyse the critical role of non-state and non-market participants in the functioning of a democratic government and society, such as the media, civil society, socio-religious institutions, and community institutions."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-6.1",
      "title": "Indian Ethos and Diversity",
      "description": "Understands how the Indian ethos respected diversity.",
      "competencies": [
        "Understands how the Indian ethos and the cultural integration across India did not attempt uniformity, but respected and promoted a rich diversity in Indian society, and how this harmonisation and unity in diversity, with a historical respect for all cultures, women have counted among India's great strengths by promoting peaceful coexistence."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-6.2",
      "title": "Inequality and Justice in Society",
      "description": "Understand forms of inequality, injustice, and discrimination.",
      "competencies": [
        "Understand that despite C-6.1, forms of inequality, injustice, and discrimination have occurred in different sections of society at different times (due to internal as well as outside forces such as colonisation), leading to political, social, and cultural efforts, struggles, movements, and mechanisms at various levels towards equity, inclusion, justice, and harmony, with varying outcomes and degrees of success."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-7.1",
      "title": "Key Features of Economy",
      "description": "Defines key features of the economy.",
      "competencies": [
        "Defines key features of the economy, such as, production, distribution, demand, supply, trade, and commerce, and factors that influence these aspects (including technology)."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-7.2",
      "title": "Three Sectors of Production",
      "description": "Evaluates the importance of the three sectors.",
      "competencies": [
        "Evaluates the importance of the three sectors of production (primary, secondary, and tertiary) in any country's economy, especially India."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-7.3",
      "title": "Organised vs Unorganised Sectors",
      "description": "Distinguishes between organised and unorganised sectors.",
      "competencies": [
        "Distinguishes between 'unorganised' and 'organised' sectors of the economy and their role in production for the local market in small, medium, and large-scale production centres (industries), and recognises the special importance of the so-called 'unorganised' sector in Indian economy and its connections with the self-organising features of Indian society."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-7.4",
      "title": "Large-scale Trade and Commerce",
      "description": "Trace the beginning and importance of large-scale trade.",
      "competencies": [
        "Trace the beginning and importance of large- scale trade and commerce (including e- commerce) between one country and another - the key items of trade in the beginning, and the changes from time to time."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-8.1",
      "title": "Data Analysis on Economy",
      "description": "Gather, comprehend, and analyse data related to income.",
      "competencies": [
        "Gather, comprehend, and analyse data related to income, capital, poverty, and employment in one's locality, region and at the national level."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-8.3",
      "title": "Economy of Ancient India",
      "description": "Understand features in context of ancient India.",
      "competencies": [
        "Understand these features in the context of ancient India, with its thriving trade, both internal and external, and its well- established trade practices and networks, business conventions, and diverse industries, all of which made India one of the world's leading economies up to the colonial period."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-8.4",
      "title": "India's Economic Progress",
      "description": "Describes India's recent path towards economic progress.",
      "competencies": [
        "Describes India's recent path towards again becoming one of the three largest economies of the world, and how individuals can contribute to this economic progress."
      ],
      "unit_name": "",
      "chapter_name": ""
    },
    {
      "code": "C-8.5",
      "title": "Economic Development and Environment",
      "description": "Appreciates connections between development and environment.",
      "competencies": [
        "Appreciates the connections between economic development and the environment, and the broader indicators of societal wellbeing beyond GDP growth and income."
      ],
      "unit_name": "",
      "chapter_name": ""
    }
  ]
}
